import React, { useState } from 'react';
import axios from 'axios';
import { Search, Popcorn } from 'lucide-react';
import MovieCard from './components/MovieCard';

function App() {
  const [movie, setMovie] = useState('');
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [hasSearched, setHasSearched] = useState(false);

  const fetchRecommendations = async (e) => {
    e.preventDefault();
    if (!movie.trim()) return;

    setLoading(true);
    setError('');
    setHasSearched(true);
    setRecommendations([]);

    try {
      const response = await axios.post('http://localhost:5000/recommend', {
        movie: movie
      });
      setRecommendations(response.data.recommendations || []);
    } catch (err) {
      console.error(err);
      if (err.response && err.response.status === 404) {
        setError("Movie not found in the database. Please try another one!");
      } else {
        setError('Failed to fetch recommendations. Is the backend running?');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-container">
      <header className="header">
        <h1>AI Movie Recommender</h1>
        <p>Discover your next favorite film using the power of AI</p>
      </header>

      <main className="search-section">
        <form onSubmit={fetchRecommendations} className="search-box">
          <input
            type="text"
            className="search-input"
            value={movie}
            onChange={(e) => setMovie(e.target.value)}
            placeholder="Enter a movie you love..."
          />
          <button type="submit" className="search-btn" disabled={loading}>
            {loading ? (
              <div className="spinner" style={{ width: '20px', height: '20px', borderWidth: '2px' }}></div>
            ) : (
              <>
                <Search size={20} />
                <span>Search</span>
              </>
            )}
          </button>
        </form>
        {error && <div className="error-message">{error}</div>}
      </main>

      {hasSearched && !loading && !error && recommendations.length === 0 && (
        <div style={{ textAlign: 'center', color: 'var(--text-secondary)' }}>
          <Popcorn size={48} style={{ margin: '0 auto 1rem', opacity: 0.5 }} />
          <p>No recommendations found for "{movie}". Try a different movie!</p>
        </div>
      )}

      {recommendations.length > 0 && (
        <div className="results-grid">
          {recommendations.map((rec, index) => (
            <MovieCard key={index} movie={rec} delay={index * 0.1} />
          ))}
        </div>
      )}
    </div>
  );
}

export default App;
